Python script:

#!/usr/bin/env python3
import argparse
import json
import os
import platform
import re
import shutil
import subprocess
import sys
from datetime import datetime
from pathlib import Path

# Simple local advisory database stub.
# In practice, integrate with APIs like NVD, OSV, distro security trackers, or vendor advisories.
ADVISORIES = {
    # package: list of dicts with vulnerable version patterns and CVE info
    "openssl": [
        {"vuln_regex": r"^1\.0\.", "cves": ["CVE-2016-2107", "CVE-2016-2105"], "fix": "Upgrade to >= 1.1.1"},
        {"vuln_regex": r"^1\.1\.0", "cves": ["CVE-2018-0734"], "fix": "Upgrade to >= 1.1.1"}
    ],
    "sudo": [
        {"vuln_regex": r"^1\.8\.(1[0-9]|2[0-9])", "cves": ["CVE-2021-3156"], "fix": "Upgrade to >= 1.9.5p2"}
    ],
    "bash": [
        {"vuln_regex": r"^4\.3", "cves": ["CVE-2014-6271", "CVE-2014-7169"], "fix": "Upgrade to >= 4.4"}
    ]
}

def which(cmd):
    return shutil.which(cmd)

def run(cmd):
    try:
        out = subprocess.check_output(cmd, stderr=subprocess.STDOUT, text=True)
        return out.strip()
    except Exception:
        return ""

def parse_version(s):
    m = re.search(r"(\d+\.\d+(\.\d+)?([a-zA-Z0-9.-]+)?)", s)
    return m.group(1) if m else None

def get_os_info():
    return {
        "platform": platform.system(),
        "platform_release": platform.release(),
        "platform_version": platform.version(),
        "distribution": " ".join(platform.platform().split("-")[:1]),
        "python": platform.python_version(),
        "hostname": platform.node(),
        "arch": platform.machine(),
    }

def get_pkg_manager():
    # Detect common package managers
    for pm in ["apt", "dpkg", "rpm", "dnf", "yum", "pacman", "zypper", "brew", "port"]:
        if which(pm):
            return pm
    return None

def list_installed_packages(pm):
    pkgs = {}
    try:
        if pm in ("apt", "dpkg"):
            out = run(["dpkg-query", "-W", "-f=${Package} ${Version}\n"])
            for line in out.splitlines():
                parts = line.split()
                if len(parts) >= 2:
                    pkgs[parts[0]] = parts[1]
        elif pm in ("rpm", "dnf", "yum", "zypper"):
            out = run(["rpm", "-qa", "--qf", "%{NAME} %{VERSION}-%{RELEASE}\n"])
            for line in out.splitlines():
                parts = line.split()
                if len(parts) >= 2:
                    pkgs[parts[0]] = parts[1]
        elif pm == "pacman":
            out = run(["pacman", "-Q"])
            for line in out.splitlines():
                parts = line.split()
                if len(parts) >= 2:
                    pkgs[parts[0]] = parts[1]
        elif pm == "brew":
            out = run(["brew", "list", "--versions"])
            for line in out.splitlines():
                parts = line.split()
                if len(parts) >= 2:
                    pkgs[parts[0]] = parts[1]
        elif pm == "port":
            out = run(["port", "installed"])
            for line in out.splitlines():
                m = re.match(r"\s*(\S+) @(\S+)", line)
                if m:
                    pkgs[m.group(1)] = m.group(2)
    except Exception:
        pass
    return pkgs

def get_common_software_versions():
    tools = {
        "openssl": ["openssl", ["openssl", "version"]],
        "python": ["python3", ["python3", "--version"]],
        "node": ["node", ["node", "--version"]],
        "npm": ["npm", ["npm", "--version"]],
        "git": ["git", ["git", "--version"]],
        "docker": ["docker", ["docker", "--version"]],
        "kubectl": ["kubectl", ["kubectl", "version", "--client", "--short"]],
        "java": ["java", ["java", "-version"]],
        "bash": ["bash", ["bash", "--version"]],
        "sudo": ["sudo", ["sudo", "--version"]],
    }
    versions = {}
    for name, (cmd, argv) in tools.items():
        if which(cmd):
            out = run(argv)
            ver = parse_version(out)
            versions[name] = ver or out.strip()
    return versions

def check_against_advisories(software_map):
    findings = []
    for name, ver in software_map.items():
        if name in ADVISORIES and ver:
            for adv in ADVISORIES[name]:
                if re.search(adv["vuln_regex"], ver):
                    findings.append({
                        "component": name,
                        "version": ver,
                        "cves": adv["cves"],
                        "severity": "HIGH",
                        "recommendation": adv["fix"]
                    })
    return findings

def check_configurations():
    findings = []
    # Example checks
    # 1) World-writable sensitive dirs
    sensitive_dirs = ["/etc", "/usr/local/bin", "/bin", "/sbin", "/usr/bin"]
    for d in sensitive_dirs:
        try:
            st = os.stat(d)
            if st.st_mode & 0o002:
                findings.append({
                    "issue": f"World-writable directory: {d}",
                    "severity": "HIGH",
                    "recommendation": "Remove world-writable bit (chmod o-w) and audit ownership."
                })
        except Exception:
            pass

    # 2) SSH configuration
    sshd_conf = Path("/etc/ssh/sshd_config")
    if sshd_conf.exists():
        txt = sshd_conf.read_text(errors="ignore")
        cfg = dict(re.findall(r"(?mi)^\s*([A-Za-z][A-Za-z0-9]+)\s+(.*)$", txt))
        permit_root = cfg.get("PermitRootLogin", "").strip().lower()
        if permit_root in ("yes", "prohibit-password", ""):
            findings.append({
                "issue": "Potentially unsafe SSH root login setting",
                "severity": "MEDIUM",
                "recommendation": "Set PermitRootLogin no and use key-based auth for non-root users."
            })
        pw_auth = cfg.get("PasswordAuthentication", "").strip().lower()
        if pw_auth in ("yes", ""):
            findings.append({
                "issue": "Password authentication enabled in SSH",
                "severity": "MEDIUM",
                "recommendation": "Set PasswordAuthentication no and use SSH keys."
            })

    # 3) Firewall status (Linux ufw/firewalld)
    if which("ufw"):
        status = run(["ufw", "status"])
        if "inactive" in status.lower():
            findings.append({
                "issue": "Firewall (ufw) inactive",
                "severity": "MEDIUM",
                "recommendation": "Enable ufw and define allow-list rules."
            })
    elif which("firewalld"):
        status = run(["firewall-cmd", "--state"])
        if "running" not in status.lower():
            findings.append({
                "issue": "firewalld not running",
                "severity": "MEDIUM",
                "recommendation": "Start firewalld and configure zones/services appropriately."
            })

    # 4) Docker daemon rootless check
    if which("docker"):
        info = run(["docker", "info"])
        if "rootless" not in info.lower():
            findings.append({
                "issue": "Docker not running in rootless mode",
                "severity": "LOW",
                "recommendation": "Consider rootless Docker where feasible."
            })

    return findings

def gather_data():
    data = {
        "timestamp": datetime.utcnow().isoformat() + "Z",
        "system": get_os_info(),
        "package_manager": get_pkg_manager(),
        "packages": {},
        "software_versions": get_common_software_versions(),
    }
    if data["package_manager"]:
        data["packages"] = list_installed_packages(data["package_manager"])
    return data

def correlate_vulns(data):
    sw_map = dict(data["software_versions"])
    # Also check a few critical packages by name if present
    for key in ("openssl", "sudo", "bash"):
        if key not in sw_map and key in data["packages"]:
            sw_map[key] = data["packages"][key]

    findings = check_against_advisories(sw_map)
    return findings

def main():
    parser = argparse.ArgumentParser(description="System vulnerability assessment script")
    parser.add_argument("--output", "-o", default="report.json", help="Output report file")
    parser.add_argument("--pretty", action="store_true", help="Pretty-print JSON")
    args = parser.parse_args()

    data = gather_data()
    vuln_findings = correlate_vulns(data)
    config_findings = check_configurations()

    report = {
        "metadata": {
            "generated_at": data["timestamp"],
            "host": data["system"]["hostname"],
            "platform": data["system"]["platform"],
            "release": data["system"]["platform_release"],
        },
        "inventory": {
            "software_versions": data["software_versions"],
            "package_manager": data["package_manager"],
            "package_count": len(data["packages"]),
        },
        "findings": {
            "vulnerabilities": vuln_findings,
            "config_issues": config_findings
        },
        "remediation_summary": [
            "Upgrade vulnerable packages to patched versions.",
            "Harden SSH settings (disable root login, disable password auth).",
            "Ensure a host firewall is enabled and configured.",
            "Reduce world-writable permissions on sensitive directories.",
            "Consider running Docker in rootless mode where appropriate."
        ]
    }

    with open(args.output, "w") as f:
        if args.pretty:
            json.dump(report, f, indent=2)
        else:
            json.dump(report, f)

    print(f"Wrote assessment report to {args.output}")

if __name__ == "__main__":
    if os.geteuid() != 0:
        print("Note: Run with elevated privileges for more comprehensive checks.", file=sys.stderr)
    main()

How to use:
- Save the script to a file, for example assessor.py
- Run: python3 assessor.py --pretty
- Review report.json for identified vulnerabilities and configuration issues
- Extend ADVISORIES with your organization’s curated CVE data or connect to public feeds for live matching

