      if (!topic || !store.questions[topic] || store.questions[topic].length === 0) {
        practiceArea.textContent = 'No questions for this topic yet.';
        return;
      }
      store.questions[topic].forEach((item, idx) => {
        const div = document.createElement('div');
        div.className = 'question';
        const q = document.createElement('div');
        q.textContent = item.q;
        const input = document.createElement('textarea');
        input.rows = 3;
        const btn = document.createElement('button');
        btn.textContent = 'Check';
        const feedback = document.createElement('div');
        btn.addEventListener('click', () => {
          // Simple correctness heuristic (placeholder): non-empty -> correct
