          store.practiceStats.total += 1;
          if (correct) store.practiceStats.correct += 1;
          save();
          renderDashboard();
          feedback.textContent = correct ? 'Looks good. Compare with sample answer: ' + item.a : 'Try to add more detail or structure.';
        });
        div.appendChild(q);
        div.appendChild(input);
        div.appendChild(btn);
        div.appendChild(feedback);
        practiceArea.appendChild(div);
      });
