      const a = prompt('Enter a sample answer or rubric');
      if (q && a) {
        store.questions[topic].push({ q, a });
        save();
        renderPractice(topic);
      }
    });

    // Mock exam
    let examTimer = null, timeRemaining = 0;
    function formatTime(s) {
      const m = Math.floor(s/60);
      const sec = s % 60;
      return `${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}`;
    }
    document.getElementById('startExamBtn').addEventListener('click', () => {
      const minutes = parseInt(document.getElementById('examDuration').value, 10);
      if (!minutes || minutes < 1) { alert('Enter a valid duration'); return; }
      const area = document.getElementById('examArea');
      area.classList.remove('hidden');
      const questionsEl = document.getElementById('examQuestions');
      questionsEl.innerHTML = '';

      const selectedTopics = store.topics.slice(0, Math.min(5, store.topics.length));
      const examQs = [];
      selectedTopics.forEach(t => {
        const bank = store.questions[t] || [];
        if (bank.length) {
          examQs.push(bank[0]);
        } else {
          examQs.push({ q: `Explain the main ideas of ${t}.`, a: 'Varies' });
        }
      });

      examQs.forEach((item, i) => {
        const wrap = document.createElement('div');
        wrap.className = 'question';
        const q = document.createElement('div');
        q.textContent = (i+1) + '. ' + item.q;
        const input = document.createElement('textarea');
        input.rows = 4;
        input.dataset.idx = i;
        wrap.appendChild(q);
        wrap.appendChild(input);
        questionsEl.appendChild(wrap);
      });

      timeRemaining = minutes * 60;
      document.getElementById('timeLeft').textContent = formatTime(timeRemaining);
      if (examTimer) clearInterval(examTimer);
      examTimer = setInterval(() => {
        timeRemaining -= 1;
        document.getElementById('timeLeft').textContent = formatTime(timeRemaining);
        if (timeRemaining <= 0) {
          clearInterval(examTimer);
          alert('Time is up! Submitting your exam.');
          document.getElementById('submitExamBtn').click();
        }
      }, 1000);
    });

    document.getElementById('submitExamBtn').addEventListener('click', () => {
      if (examTimer) clearInterval(examTimer);
      store.examsTaken += 1;
      save();
      renderDashboard();
      const area = document.getElementById('examArea');
      area.classList.add('hidden');
      alert('Exam submitted. Review your answers and improve your prep.');
    });

    // Reset
    document.getElementById('resetDataBtn').addEventListener('click', () => {
      if (confirm('Reset all data?')) {
        localStorage.removeItem('prepStore');
        store.topics = [];
        store.questions = {};
        store.practiceStats = { correct: 0, total: 0 };
        store.examsTaken = 0;
        renderDashboard();
        renderTopicSelect();
        document.getElementById('studyPlan').classList.add('hidden');
        document.getElementById('practiceArea').innerHTML = '';
        document.getElementById('examArea').classList.add('hidden');
      }
    });

    // Initialize
    load();
    // Auto-render practice for first topic if exists
    if (store.topics[0]) {
      document.getElementById('topicSelect').value = store.topics[0];
      renderPractice(store.topics[0]);
    }
