- Output: any matches found.

Code:
import hashlib
import sys

def hash_password(password: str, algo: str) -> str:
    p = password.encode('utf-8')
    if algo == 'md5':
        return hashlib.md5(p).hexdigest()
    if algo == 'sha1':
        return hashlib.sha1(p).hexdigest()
    if algo == 'sha256':
        return hashlib.sha256(p).hexdigest()
    if algo == 'sha512':
        return hashlib.sha512(p).hexdigest()
    raise ValueError(f"Unsupported algorithm: {algo}")

def load_hashes(hash_file):
    targets = {}
    with open(hash_file, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line or ':' not in line:
                continue
            algo, h = line.split(':', 1)
            algo = algo.lower().strip()
            h = h.strip().lower()
            targets.setdefault(algo, set()).add(h)
    return targets

def crack_hashes(hash_file, wordlist_file):
    targets = load_hashes(hash_file)
    found = []

    with open(wordlist_file, 'r', encoding='utf-8', errors='ignore') as wl:
        for candidate in wl:
            candidate = candidate.strip()
            if not candidate:
                continue
            for algo, hashes in targets.items():
                h = hash_password(candidate, algo)
                if h in hashes:
                    found.append((algo, h, candidate))
                    hashes.remove(h)  # prevent duplicate reporting
    return found

def main():
    if len(sys.argv) != 3:
        print("Usage: python crack.py <hashes.txt> <wordlist.txt>")
        sys.exit(1)

    hash_file = sys.argv[1]
    wordlist_file = sys.argv[2]

    matches = crack_hashes(hash_file, wordlist_file)
    if not matches:
        print("No matches found.")
    else:
        print("Matches:")
        for algo, h, pwd in matches:
            print(f"{algo}:{h} => {pwd}")

if __name__ == "__main__":
    main()

