#!/usr/bin/env python3
import os
import subprocess
import shutil

def run(cmd):
    try:
        out = subprocess.check_output(cmd, shell=True, stderr=subprocess.STDOUT, text=True, timeout=15)
        return out.strip()
    except Exception as e:
        return f"Error: {e}"

def check_updates():
    if shutil.which("apt"):
        return run("apt list --upgradable 2>/dev/null | tail -n +2")
    if shutil.which("dnf"):
        return run("dnf check-update || true")
    if shutil.which("yum"):
        return run("yum check-update || true")
    if shutil.which("zypper"):
        return run("zypper lu || true")
    return "No known package manager found."

def check_firewall():
    if shutil.which("ufw"):
        return "ufw:\n" + run("ufw status verbose")
    if shutil.which("firewall-cmd"):
        return "firewalld:\n" + run("firewall-cmd --state") + "\n" + run("firewall-cmd --list-all")
    return "No ufw or firewalld detected."

def check_ssh():
    conf = "/etc/ssh/sshd_config"
    out = []
    if os.path.exists(conf):
        with open(conf, "r", encoding="utf-8", errors="ignore") as f:
            lines = [l.strip() for l in f if l.strip() and not l.strip().startswith("#")]
        for key in ["Port", "Protocol", "PermitRootLogin", "PasswordAuthentication", "PubkeyAuthentication"]:
            vals = [l for l in lines if l.lower().startswith(key.lower())]
            out.append(f"{key}: {vals[0].split(None,1)[1] if vals else 'default'}")
    else:
        out.append("sshd_config not found")
    status = run("systemctl is-active ssh || systemctl is-active sshd || true")
    out.append(f"SSH service status: {status}")
    return "\n".join(out)

def check_listening_ports():
    if shutil.which("ss"):
        return run("ss -tulpen")
    if shutil.which("netstat"):
        return run("netstat -tulpen")
    return "Neither ss nor netstat available."

def check_users_sudo():
    sudoers = run("getent group sudo || getent group wheel || true")
    return sudoers if sudoers else "No sudo/wheel group info."

def main():
    print("== Patch/Update Status ==")
    print(check_updates(), end="\n\n")

    print("== Firewall ==")
    print(check_firewall(), end="\n\n")

    print("== SSH Configuration ==")
    print(check_ssh(), end="\n\n")

    print("== Listening Ports ==")
    print(check_listening_ports(), end="\n\n")

    print("== Admin Group Members ==")
    print(check_users_sudo(), end="\n\n")

    print("Audit complete. Review findings and apply security best practices.")

if __name__ == "__main__":
    main()

